const body = $json.body || $json;
let canal = 'desconocido', telefono = '', nombre = 'Cliente', mensaje = '',
    idMensaje = '', tipoMensaje = 'text', audioUrl = '', imageUrl = '',
    imageCaption = '', numeroNegocio = '';

if (body.whatsappInboundMessage) {
  const wa = body.whatsappInboundMessage;
  canal         = 'whatsapp';
  telefono      = wa.from || '';
  nombre        = wa.customerProfile?.name || 'Cliente';
  mensaje       = wa.text?.body || wa.image?.caption || '';
  idMensaje     = wa.wamid || wa.id || '';
  tipoMensaje   = wa.type || 'text';
  audioUrl      = wa.audio?.link || '';
  imageUrl      = wa.image?.link || '';
  imageCaption  = wa.image?.caption || '';
  numeroNegocio = wa.to || '';
} else if (body.object === 'page' || body.entry) {
  canal = 'messenger';
  try {
    const ev      = body.entry?.[0]?.messaging?.[0];
    telefono      = ev?.sender?.id || '';
    nombre        = 'Usuario Messenger';
    mensaje       = ev?.message?.text || '';
    idMensaje     = ev?.message?.mid || '';
    numeroNegocio = ev?.recipient?.id || '';
  } catch(e) {}
} else if (body.canal === 'webchat' || body.source === 'webchat') {
  canal         = 'webchat';
  telefono      = body.session_id || body.userId || '';
  nombre        = body.nombre || 'Visitante';
  mensaje       = body.mensaje || body.message || '';
  idMensaje     = body.msg_id || Date.now().toString();
  numeroNegocio = 'webchat';
} else if (body.canal === 'formulario' || body.source === 'form') {
  canal         = 'formulario';
  telefono      = body.telefono || body.phone || '';
  nombre        = body.nombre || '';
  mensaje       = body.mensaje || body.consulta || '';
  idMensaje     = body.form_id || Date.now().toString();
  numeroNegocio = 'formulario';
}

return [{ json: { canal, telefono, nombre, mensaje, idMensaje, tipoMensaje, audioUrl, imageUrl, imageCaption, numeroNegocio, ts: new Date().toISOString() } }];

const normData = $('Normalizar Canal').first().json;
const transcript = $json.text || $json.transcription || '[Audio no transcribible]';
return [{ json: { ...normData, mensajeFinal: transcript } }];

const normData = $('Normalizar Canal').first().json;
const desc = $json.choices?.[0]?.message?.content || normData.imageCaption || '[Imagen recibida]';
const mensajeFinal = '[Imagen] ' + desc;
return [{ json: { ...normData, mensajeFinal } }];

const msg = ($json.mensajeFinal || $json.mensaje || '').toLowerCase();

const COTIZ = ['cotiz','precio','cuanto','cuánto','cuesta','valen','vale','presupuesto','cuanto sale','cuánto sale','cobran','cobras'];
const STOCK = ['tienen','hay','stock','disponible','existe','manejan','llanta','llantas','rin','rines','medida','seminueva','nueva','usada','r13','r14','r15','r16','r17','r18','r19','r20','175','185','195','205','215','225','235','245','255','265'];

let intencion = 'general';
if (COTIZ.some(k => msg.includes(k))) intencion = 'solicitud_cotizacion';
else if (STOCK.some(k => msg.includes(k))) intencion = 'consulta_stock';

return [{ json: { ...$json, intencion } }];

const filas = $input.all();
const base  = $('Clasificar Intención').first().json;

const inventario = filas.length
  ? filas.map(f => {
      const r = f.json;
      return `• ${r.Producto||r.producto||'—'} | Medida: ${r.Medida||r.medida||'—'} | Disponible: ${r.Stock||r.stock||'0'} | Precio: ${r.Precio||r.precio||'Consultar'}`;
    }).join('\n')
  : 'Sin datos de inventario disponibles.';

return [{ json: { ...base, contexto_extra: `INVENTARIO ACTUAL (cita solo lo que aparece aquí):\n${inventario}` } }];

return [{ json: {
  telefono:      $json.telefono || '',
  nombre:        $json.nombre || 'Cliente',
  canal:         $json.canal || '',
  numeroNegocio: $json.numeroNegocio || '',
  mensajeFinal:  $json.mensajeFinal || $json.mensaje || '',
  contextoExtra: $json.contexto_extra || '',
  intencion:     $json.intencion || 'general'
} }];

const ctx = $('Consolidar Contexto').first().json;
const raw = $json.value || null;
let historial = [];
if (raw) { try { historial = JSON.parse(raw); } catch(e) {} }

const ultimos = historial.slice(-8);
const historialTexto = ultimos.length > 0
  ? ultimos.map(m => (m.rol === 'user' ? 'Cliente' : 'Asistente') + ': ' + m.contenido).join('\n') + '\n\n'
  : '';

return [{ json: {
  ...ctx,
  historial,
  historialTexto,
  promptFinal: historialTexto + (ctx.contextoExtra ? ctx.contextoExtra + '\n\n' : '') + 'Mensaje del cliente: ' + ctx.mensajeFinal
} }];

const ctx = $('Consolidar Contexto').first().json;
const prepData = $('Preparar Prompt con Historial').first().json;
const respuesta = $json.message?.content || '';
const historialActual = prepData.historial || [];
const nuevoHistorial = [
  ...historialActual.slice(-9),
  { rol: 'user', contenido: ctx.mensajeFinal },
  { rol: 'assistant', contenido: respuesta }
];
return [{ json: {
  ...ctx,
  respuesta,
  nuevoHistorial: JSON.stringify(nuevoHistorial)
} }];
